import numpy as np

def weighted_average(predictions: list[np.ndarray], weights: list[float]) -> np.ndarray:
    w = np.array(weights, dtype=np.float64)
    w = w / w.sum()
    stacked = np.array(predictions)  # (K, N)
    return (w[:, np.newaxis] * stacked).sum(axis=0)

def weighted_vote(probas: list[np.ndarray], weights: list[float]) -> np.ndarray:
    w = np.array(weights, dtype=np.float64)
    w = w / w.sum()
    stacked = np.array(probas)  # (K, N, C)
    avg = (w[:, np.newaxis, np.newaxis] * stacked).sum(axis=0)  # (N, C)
    return np.argmax(avg, axis=1)
